1	import type { ModelCapability } from '../model-capabilities/types';
2	import type { ModelSlot } from './errors';
3	
4	export type CapabilityRequirement =
5	  | { kind: 'capability'; field: keyof Pick<ModelCapability, 'vision' | 'thinking' | 'structuredOutputs' | 'toolCalling' | 'outputCap' | 'pdf' | 'promptCaching'>; label: string }
6	  | { kind: 'context'; minExclusive: number; label: string };
7	
8	export function requiredCapabilitiesFor(slot: ModelSlot): CapabilityRequirement[] {
9	  switch (slot) {
10	    case 'interview':
11	      return [
12	        { kind: 'capability', field: 'toolCalling', label: 'tools' },
13	        { kind: 'capability', field: 'structuredOutputs', label: 'structured outputs' },
14	        { kind: 'capability', field: 'vision', label: 'vision' },
15	        { kind: 'context', minExclusive: 100_000, label: 'context > 100K' },
16	      ];
17	    case 'extraction':
18	      return [
19	        { kind: 'capability', field: 'structuredOutputs', label: 'structured outputs' },
20	        { kind: 'context', minExclusive: 100_000, label: 'context > 100K' },
21	      ];
22	    case 'synthesis':
23	      return [
24	        { kind: 'context', minExclusive: 400_000, label: 'context > 400K' },
25	        { kind: 'capability', field: 'structuredOutputs', label: 'structured outputs' },
26	        { kind: 'capability', field: 'thinking', label: 'reasoning' },
27	        { kind: 'capability', field: 'outputCap', label: 'output cap' },
28	      ];
29	    case 'vision':
30	      return [{ kind: 'capability', field: 'vision', label: 'vision' }];
31	    case 'macro':
32	      // Macro understanding (source outlines, relationship extraction, coverage
33	      // audits) emits deep nested JSON. It MUST have real structured-output
34	      // support — this is the exact capability whose absence made the Qwen
35	      // json_object route throw AllCandidatesFailedError. See AGENT_ERROR_LOG.md.
36	      return [{ kind: 'capability', field: 'structuredOutputs', label: 'structured outputs' }];
37	    case 'general':
38	    case 'translation':
39	      return [];
40	  }
41	}
