43	export function missingRequirements(
44	  model: Pick<
45	    ModelCapability,
46	    | 'vision'
47	    | 'thinking'
48	    | 'structuredOutputs'
49	    | 'toolCalling'
50	    | 'outputCap'
51	    | 'pdf'
52	    | 'promptCaching'
53	    | 'contextLength'
54	  >,
55	  slot: ModelSlot,
56	): string[] {
57	  const missing: string[] = [];
58	  for (const req of requiredCapabilitiesFor(slot)) {
59	    if (req.kind === 'capability') {
60	      if (!model[req.field]) missing.push(req.label);
61	    } else if (model.contextLength == null || model.contextLength <= req.minExclusive) {
62	      missing.push(req.label);
63	    }
64	  }
65	  return missing;
66	}
