1	import { eq, inArray } from 'drizzle-orm';
2	import type { OracleDb } from '@oracle/db';
3	import { modelCapabilities, settings } from '@oracle/db/schema';
4	import { getAuxiliaryModelDef } from './auxiliary';
5	import {
6	  ENFORCE_MODEL_CAPABILITIES_SETTING_KEY,
7	  MODEL_POOL_MACRO_SETTING_KEY,
8	  MODEL_POOL_SETTING_KEYS,
9	  REASONING_EFFORT_SETTING_KEYS,
10	  ROUTE_SETTING_KEYS,
11	} from './defaults';
12	import { ModelCapabilityError, NoConfiguredModelError, type ModelSlot } from './errors';
13	import { missingRequirements } from './capability-requirements';
14	import { providerModelIdForRoute, resolveModelRoute, type SyntheticRouteCaps } from './resolve';
15	import type { ModelCapability } from '../model-capabilities/types';
16	import type { OracleModelRole, OracleModelRoute, ReasoningEffort } from './types';
