18	export interface RouteCandidate {
19	  route: OracleModelRoute;
20	  slot: ModelSlot;
21	  isPrimary: boolean;
22	  approvedModelId: string;
23	}
24	
25	export interface SkippedRouteCandidate {
26	  slot: ModelSlot;
27	  modelIdOrRouteId: string;
28	  reason: string;
29	}
