37	function isReasoningEffort(v: unknown): v is ReasoningEffort {
38	  return v === 'off' || v === 'low' || v === 'medium' || v === 'high';
39	}
40	
41	function isPipelineSlot(slot: ModelSlot): slot is OracleModelRole {
42	  return slot === 'interview' || slot === 'extraction' || slot === 'synthesis';
43	}
44	
45	function roleForSlot(slot: ModelSlot): OracleModelRole {
46	  return isPipelineSlot(slot) ? slot : 'extraction';
47	}
48	
49	function settingKeysForSlot(slot: ModelSlot): {
50	  routeKey: string;
51	  effortKey?: string;
52	  poolKey?: string;
53	} {
54	  if (isPipelineSlot(slot)) {
55	    return {
56	      routeKey: ROUTE_SETTING_KEYS[slot],
57	      effortKey: REASONING_EFFORT_SETTING_KEYS[slot],
58	      poolKey: MODEL_POOL_SETTING_KEYS[slot],
59	    };
60	  }
61	  const def = getAuxiliaryModelDef(slot);
62	  if (!def) throw new NoConfiguredModelError(slot, 'unknown auxiliary model id');
63	  return {
64	    routeKey: def.routeSettingKey,
65	    effortKey: def.reasoningEffortSettingKey,
66	    // The macro slot is the one auxiliary with a fallback pool (resilience for
67	    // the holistic layer). Other aux slots stay single-pick.
68	    poolKey: slot === 'macro' ? MODEL_POOL_MACRO_SETTING_KEY : undefined,
69	  };
70	}
