72	function capToRouteCaps(cap: ModelCapability): SyntheticRouteCaps {
73	  const normalized = normalizeProviderCapabilities(cap);
74	  return {
75	    supportsVision: normalized.vision,
76	    supportsToolCalling: normalized.toolCalling,
77	    supportsStructuredOutput: normalized.structuredOutputs,
78	    supportsReasoningControls: normalized.thinking,
79	    enabled: true,
80	  };
81	}
