88	/**
89	 * Runtime guards must be stricter than third-party catalog enrichment. Qwen's
90	 * text-only models can be over-tagged at the family level; only VL/omni models
91	 * should satisfy the image-vision slot.
92	 */
93	function normalizeProviderCapabilities(cap: ModelCapability): ModelCapability {
94	  if (cap.provider === 'qwen' && cap.vision && !isQwenVisionModel(cap.id)) {
95	    return { ...cap, vision: false };
96	  }
97	  return cap;
98	}
