106	async function readSettings(db: OracleDb, keys: string[]): Promise<Map<string, unknown>> {
107	  const rows = await db
108	    .select({ key: settings.key, value: settings.value })
109	    .from(settings)
110	    .where(inArray(settings.key, keys));
111	  return new Map(rows.map((r) => [r.key, r.value]));
112	}
