114	async function loadCapabilityMap(db: OracleDb, ids: string[]): Promise<Map<string, ModelCapability>> {
115	  if (ids.length === 0) return new Map();
116	  const unique = Array.from(new Set(ids));
117	  const rows = await db
118	    .select()
119	    .from(modelCapabilities)
120	    .where(inArray(modelCapabilities.id, unique));
121	  return new Map(
122	    rows.map((r) => [
123	      r.id,
124	      {
125	        id: r.id,
126	        provider: r.provider as ModelCapability['provider'],
127	        displayName: r.displayName,
128	        contextLength: r.contextLength,
129	        maxOutputTokens: r.maxOutputTokens,
130	        promptPer1mUsd: r.promptPer1mUsd != null ? Number(r.promptPer1mUsd) : null,
131	        completionPer1mUsd: r.completionPer1mUsd != null ? Number(r.completionPer1mUsd) : null,
132	        vision: r.vision,
133	        pdf: r.pdf,
134	        thinking: r.thinking,
135	        structuredOutputs: r.structuredOutputs,
136	        toolCalling: r.toolCalling,
137	        promptCaching: r.promptCaching,
138	        outputCap: r.outputCap,
139	        knowledgeCutoff: r.knowledgeCutoff,
140	        source: r.source as ModelCapability['source'],
141	      } satisfies ModelCapability,
142	    ]),
143	  );
144	}
