146	async function enforceCapabilitiesEnabled(db: OracleDb): Promise<boolean> {
147	  const rows = await db
148	    .select({ value: settings.value })
149	    .from(settings)
150	    .where(eq(settings.key, ENFORCE_MODEL_CAPABILITIES_SETTING_KEY))
151	    .limit(1);
152	  return rows[0]?.value !== false;
153	}
