155	function capabilityForRoute(
156	  route: OracleModelRoute,
157	  capabilityMap: Map<string, ModelCapability>,
158	): { id: string; cap: ModelCapability } | null {
159	  for (const id of catalogIdsForRoute(route)) {
160	    const cap = capabilityMap.get(id);
161	    if (cap) return { id, cap };
162	  }
163	  return null;
164	}
