166	function resolveWithKnownCaps(
167	  modelIdOrRouteId: string,
168	  role: OracleModelRole,
169	  effort: ReasoningEffort | undefined,
170	  capMap: Map<string, ModelCapability>,
171	): OracleModelRoute | null {
172	  const directCap = capMap.get(modelIdOrRouteId);
173	  return resolveModelRoute(
174	    modelIdOrRouteId,
175	    role,
176	    effort,
177	    directCap ? capToRouteCaps(directCap) : undefined,
178	  );
179	}
