181	export async function resolveRouteCandidates(
182	  db: OracleDb,
183	  slot: ModelSlot,
184	): Promise<RouteCandidateResolution> {
185	  const { routeKey, effortKey, poolKey } = settingKeysForSlot(slot);
186	  const keys = [
187	    routeKey,
188	    ...(effortKey ? [effortKey] : []),
189	    ...(poolKey ? [poolKey] : []),
190	    ENFORCE_MODEL_CAPABILITIES_SETTING_KEY,
191	  ];
192	  const rows = await readSettings(db, keys);
193	
194	  const primaryValue = rows.get(routeKey);
195	  const primary = typeof primaryValue === 'string' ? primaryValue : null;
196	  if (!primary) throw new NoConfiguredModelError(slot, `${routeKey} is unset`);
197	
198	  const effort = effortKey && isReasoningEffort(rows.get(effortKey))
199	    ? (rows.get(effortKey) as ReasoningEffort)
200	    : undefined;
201	  const role = roleForSlot(slot);
202	  const enforceCaps = await enforceCapabilitiesEnabled(db);
203	
204	  const pool = poolKey && Array.isArray(rows.get(poolKey))
205	    ? (rows.get(poolKey) as unknown[]).filter((v): v is string => typeof v === 'string')
206	    : [];
207	
208	  if (poolKey && pool.length === 0) {
209	    throw new NoConfiguredModelError(slot, `${poolKey} is empty`);
210	  }
211	
212	  const probeIds = Array.from(new Set([primary, ...pool]));
213	  const capabilityMap = await loadCapabilityMap(db, probeIds);
214	  const primaryRoute = resolveWithKnownCaps(primary, role, effort, capabilityMap);
215	  if (!primaryRoute) throw new NoConfiguredModelError(slot, `${primary} cannot be resolved`);
216	  const primaryRouteCaps = await loadCapabilityMap(db, catalogIdsForRoute(primaryRoute));
217	  for (const [id, cap] of primaryRouteCaps) {
218	    capabilityMap.set(id, cap);
219	  }
220	
221	  const primaryCatalogIds = catalogIdsForRoute(primaryRoute);
222	  const primaryApprovedId =
223	    poolKey
224	      ? pool.find((id) => id === primary || primaryCatalogIds.includes(id))
225	      : primaryCatalogIds.find((id) => capabilityMap.has(id)) ?? primary;
226	
227	  if (poolKey && !primaryApprovedId) {
228	    throw new NoConfiguredModelError(
229	      slot,
230	      `${primary} resolves to ${primaryCatalogIds.join(' / ')} but is not in ${poolKey}`,
231	    );
232	  }
233	
234	  const ordered = poolKey
235	    ? [primaryApprovedId!, ...pool.filter((id) => id !== primaryApprovedId)]
236	    : [primary];
237	
238	  const candidates: RouteCandidate[] = [];
239	  const skipped: SkippedRouteCandidate[] = [];
240	  const seenConcrete = new Set<string>();
241	
242	  for (const [index, id] of ordered.entries()) {
243	    const route = index === 0
244	      ? primaryRoute
245	      : resolveWithKnownCaps(id, role, effort, capabilityMap);
246	    if (!route) {
247	      skipped.push({ slot, modelIdOrRouteId: id, reason: 'unresolvable model id' });
248	      continue;
249	    }
250	
251	    const concrete = providerModelIdForRoute(route);
252	    if (seenConcrete.has(concrete)) continue;
253	    seenConcrete.add(concrete);
254	
255	    const capMatch = capabilityForRoute(route, capabilityMap);
256	    if (enforceCaps) {
257	      if (!capMatch) {
258	        const err = new ModelCapabilityError(slot, concrete, ['catalog metadata']);
259	        if (index === 0) throw err;
260	        skipped.push({ slot, modelIdOrRouteId: id, reason: err.message });
261	        continue;
262	      }
263	      const missing = missingRequirements(normalizeProviderCapabilities(capMatch.cap), slot);
264	      if (missing.length > 0) {
265	        const err = new ModelCapabilityError(slot, capMatch.id, missing);
266	        if (index === 0) throw err;
267	        skipped.push({ slot, modelIdOrRouteId: id, reason: err.message });
268	        continue;
269	      }
270	    }
271	
272	    candidates.push({
273	      route,
274	      slot,
275	      isPrimary: index === 0,
276	      approvedModelId: poolKey ? id : capMatch?.id ?? concrete,
277	    });
278	  }
279	
280	  if (candidates.length === 0) {
281	    throw new NoConfiguredModelError(slot, 'all configured candidates were invalid');
282	  }
283	
284	  return { slot, candidates, skipped };
285	}
