287	export async function resolvePrimaryRouteFromSettings(
288	  db: OracleDb,
289	  slot: ModelSlot,
290	): Promise<OracleModelRoute> {
291	  return (await resolveRouteCandidates(db, slot)).candidates[0]!.route;
292	}
